# Deobfuscated Code

This is a **particle physics simulation** visualizing an interactive network of nodes with spring forces. Here's the cleaned-up version:

```javascript
// Constants
const TWO_PI = 6.283;
const GOLDEN_RATIO = 1.618;
const SQRT_2 = 0.707;

// Configuration
const config = {
  attractionForce: 4000,
  dampingCoefficient: 0.004,
  amplification: 0.92,
  centeringForce: 0.0003,
  maxParticles: 40,
  streamDecay: 0.04,
  cameraEasing: 0.06
};

// Nodes
const nodes = [
  { id: 'hub', label: 'Hub', r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: 'alpha', label: 'Alpha', r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: 'beta', label: 'Beta', r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: 'gamma', label: 'Gamma', r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: 'delta', label: 'Delta', r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// Spring connections between nodes
const springs = [
  { a: 'hub', b: 'alpha', rest: 160, k: 0.006 },
  { a: 'hub', b: 'beta', rest: 160, k: 0.005 },
  { a: 'hub', b: 'gamma', rest: 170, k: 0.004 },
  { a: 'hub', b: 'delta', rest: 170, k: 0.004 },
  { a: 'hub', b: 'epsilon', rest: 180, k: 0.003 },
  { a: 'alpha', b: 'beta', rest: 200, k: 0.002 },
  { a: 'gamma', b: 'delta', rest: 220, k: 0.002 },
  { a: 'beta', b: 'epsilon', rest: 200, k: 0.002 }
];

// Camera/viewport
let camera = { x: 400, y: 300, zoom: 1 };
let targetCamera = { x: 400, y: 300, zoom: 1 };

// Particles (emitted from nodes)
let particles = [];
let frameCount = 0;

// Get node by ID
function getNodeById(id) {
  return nodes.find(node => node.id === id);
}

// Apply physics forces
function updatePhysics() {
  // Repulsion between all nodes
  for (let i = 0; i < nodes.length; i++) {
    for (let j = i + 1; j < nodes.length; j++) {
      const dx = nodes[i].x - nodes[j].x;
      const dy = nodes[i].y - nodes[j].y;
      const dist = Math.sqrt(dx*dx + dy*dy) || 1;
      const force = config.attractionForce / (dist * dist);
      const fx = (dx / dist) * force;
      const fy = (dy / dist) * force;

      nodes[i].vx += fx;
      nodes[i].vy += fy;
      nodes[j].vx -= fx;
      nodes[j].vy -= fy;
    }
  }

  // Spring forces
  for (let i = 0; i < springs.length; i++) {
    const nodeA = getNodeById(springs[i].a);
    const nodeB = getNodeById(springs[i].b);

    if (!nodeA || !nodeB) continue;

    const dx = nodeB.x - nodeA.x;
    const dy = nodeB.y - nodeA.y;
    const dist = Math.sqrt(dx*dx + dy*dy) || 1;
    const strain = dist - springs[i].rest;
    const force = (springs[i].k || config.dampingCoefficient) * strain;

    nodeA.vx += (dx / dist) * force;
    nodeA.vy += (dy / dist) * force;
    nodeB.vx -= (dx / dist) * force;
    nodeB.vy -= (dy / dist) * force;
  }

  // Update positions with damping and center attraction
  for (let i = 0; i < nodes.length; i++) {
    nodes[i].vx += (400 - nodes[i].x) * config.centeringForce;
    nodes[i].vy += (300 - nodes[i].y) * config.centeringForce;

    nodes[i].vx *= config.amplification;
    nodes[i].vy *= config.amplification;

    nodes[i].x += nodes[i].vx;
    nodes[i].y += nodes[i].vy;
  }
}

// Emit particles from nodes
function emitParticles() {
  if (particles.length >= config.maxParticles) return;

  const sourceNode = nodes[Math.floor(Math.random() * nodes.length)];
  const angle = Math.random() * TWO_PI;
  const speed = 0.3 + Math.random() * SQRT_2;

  particles.push({
    x: sourceNode.x,
    y: sourceNode.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + Math.random() * GOLDEN_RATIO * SQRT_2
  });
}

// Update particles
function updateParticles() {
  for (let i = particles.length - 1; i >= 0; i--) {
    particles[i].age++;
    particles[i].vx *= 1 - config.streamDecay * 0.125;
    particles[i].vy *= 1 - config.streamDecay * 0.125;
    particles[i].x += particles[i].vx;
    particles[i].y += particles[i].vy;

    if (particles[i].age > particles[i].maxAge) {
      particles.splice(i, 1);
    }
  }
}

// Smooth camera movement
function updateCamera() {
  camera.x += (targetCamera.x - camera.x) * config.cameraEasing;
  camera.y += (targetCamera.y - camera.y) * config.cameraEasing;
  camera.zoom += (targetCamera.zoom - camera.zoom) * config.cameraEasing;
}

// Main loop
function animate() {
  updatePhysics();
  updateParticles();
  updateCamera();

  if (frameCount % 3 === 0) {
    emitParticles();
  }
  frameCount++;
}

setInterval(animate, 16); // ~60 FPS
```

## What It Does

1. **Node Physics**: Creates 6 interconnected nodes that repel each other and attract toward the center, connected by spring forces
2. **Particle Emission**: Continuously emits particles from random nodes in random directions
3. **Particle Decay**: Particles slow down and fade over time
4. **Camera Tracking**: Smoothly animates the viewport
5. **Animation Loop**: Runs physics simulation at ~60 FPS

This could be used for a network visualization, interactive graph, or abstract animated background.
